{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Enterprise Log Analysis Knowledge Base Schema",
  "description": "Schema for capturing and organizing debugging knowledge for team reuse",
  "type": "object",
  "required": ["metadata", "incident", "analysis", "resolution", "knowledge"],
  "properties": {
    "metadata": {
      "type": "object",
      "required": ["entry_id", "created_date", "analyst", "version"],
      "properties": {
        "entry_id": {
          "type": "string",
          "pattern": "^[A-Z0-9]{8}-[A-Z0-9]{4}-[A-Z0-9]{4}-[A-Z0-9]{4}-[A-Z0-9]{12}$",
          "description": "Unique identifier for knowledge base entry"
        },
        "created_date": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp of entry creation"
        },
        "last_updated": {
          "type": "string",
          "format": "date-time",
          "description": "ISO 8601 timestamp of last update"
        },
        "analyst": {
          "type": "string",
          "description": "Name or ID of the analyzing engineer"
        },
        "version": {
          "type": "string",
          "pattern": "^\\d+\\.\\d+\\.\\d+$",
          "description": "Semantic version of this entry"
        },
        "tags": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Tags for categorization and search"
        },
        "priority": {
          "type": "string",
          "enum": ["P0", "P1", "P2", "P3"],
          "description": "Incident priority level"
        }
      }
    },
    "incident": {
      "type": "object",
      "required": ["title", "description", "symptoms", "impact"],
      "properties": {
        "title": {
          "type": "string",
          "maxLength": 200,
          "description": "Brief, descriptive title of the incident"
        },
        "description": {
          "type": "string",
          "description": "Detailed description of what happened"
        },
        "symptoms": {
          "type": "array",
