            "type": "object",
            "required": ["type", "description", "evidence"],
            "properties": {
              "type": {
                "type": "string",
                "enum": [
                  "crash",
                  "performance_degradation",
                  "memory_issue",
                  "threading_issue",
                  "network_failure",
                  "authentication_failure",
                  "data_corruption",
                  "configuration_error",
                  "other"
