              },
              "description": {
                "type": "string",
                "description": "Human-readable symptom description"
              },
              "evidence": {
                "type": "array",
                "items": {
                  "type": "string"
                },
                "description": "Specific evidence supporting this symptom"
              },
              "confidence": {
                "type": "number",
                "minimum": 0.0,
                "maximum": 1.0,
                "description": "Confidence level in symptom identification"
              }
            }
          }
        },
        "impact": {
          "type": "object",
          "required": ["severity", "affected_users", "business_impact"],
          "properties": {
            "severity": {
              "type": "string",
              "enum": ["critical", "high", "medium", "low"]
            },
            "affected_users": {
              "type": "string",
              "description": "Description of affected user base"
            },
            "business_impact": {
              "type": "string",
              "description": "Business impact assessment"
            },
            "duration": {
              "type": "string",
              "description": "Duration of the incident"
            }
          }
        },
        "environment": {
          "type": "object",
          "properties": {
            "platform": {
              "type": "string",
              "enum": ["iOS", "Android", "Web", "Backend", "Multiple"]
            },
            "version": {
              "type": "string",
              "description": "Application/system version"
            },
            "deployment_environment": {
              "type": "string",
              "enum": ["production", "staging", "development", "beta"]
            },
            "device_info": {
              "type": "object",
              "properties": {
                "model": {
                  "type": "string"
                },
                "os_version": {
                  "type": "string"
                },
                "memory": {
                  "type": "string"
                }
              }
            }
          }
        }
      }
    },
    "analysis": {
      "type": "object",
      "required": ["methodology", "root_cause", "evidence_chain"],
      "properties": {
        "methodology": {
          "type": "object",
          "properties": {
            "workflow_used": {
              "type": "string",
              "enum": ["standard_2.1-2.8", "boundary_case_3.1-3.6"],
              "description": "Which debugging workflow was applied"
            },
            "steps_completed": {
              "type": "array",
              "items": {
                "type": "string"
              },
              "description": "Which analysis steps were completed"
            },
            "tools_used": {
              "type": "array",
              "items": {
                "type": "string"
              },
              "description": "Tools and scripts used in analysis"
